// Normalize performance data from different platforms
const performanceData = $input.all();
const normalizedData = [];

for (const data of performanceData) {
  const raw = data.json;
  const platform = data.json._platform || 'unknown';

  let normalized = {
    platform: platform,
    timestamp: new Date().toISOString(),
    raw_data: raw
  };

  switch(platform) {
    case 'twitter':
      const metrics = raw.data?.public_metrics || {};
      normalized = {
        ...normalized,
        content_id: raw.data?.id,
        impressions: metrics.impression_count || 0,
        engagements: metrics.like_count + metrics.reply_count + metrics.retweet_count + metrics.quote_count,
        likes: metrics.like_count || 0,
        retweets: metrics.retweet_count || 0,
        replies: metrics.reply_count || 0,
        engagement_rate: metrics.impression_count > 0 ? 
          ((metrics.like_count + metrics.reply_count + metrics.retweet_count + metrics.quote_count) / metrics.impression_count) * 100 : 0,
        reach: metrics.impression_count || 0
      };
      break;

    case 'linkedin':
      const stats = raw.elements?.[0] || {};
      normalized = {
        ...normalized,
        content_id: stats.share,
        impressions: stats.impressionCount || 0,
        engagements: stats.clickCount + stats.likeCount + stats.commentCount + stats.shareCount,
        likes: stats.likeCount || 0,
        comments: stats.commentCount || 0,
        shares: stats.shareCount || 0,
        clicks: stats.clickCount || 0,
        engagement_rate: stats.impressionCount > 0 ? 
          ((stats.clickCount + stats.likeCount + stats.commentCount + stats.shareCount) / stats.impressionCount) * 100 : 0,
        reach: stats.uniqueImpressions || 0
      };
      break;

    case 'youtube':
      const rows = raw.rows || [];
      const videoStats = rows.reduce((acc, row) => {
        const videoId = row[1];
        if (!acc[videoId]) {
          acc[videoId] = {
            views: 0,
            watch_time: 0,
            likes: 0,
            subscribers: 0
          };
        }
        acc[videoId].views += parseInt(row[2]) || 0;
        acc[videoId].watch_time += parseInt(row[3]) || 0;
        acc[videoId].likes += parseInt(row[4]) || 0;
        acc[videoId].subscribers += parseInt(row[5]) || 0;
        return acc;
      }, {});

      // Convert to array of video performances
      for (const [videoId, stats] of Object.entries(videoStats)) {
        normalizedData.push({
          platform: 'youtube',
          content_id: videoId,
          timestamp: new Date().toISOString(),
          views: stats.views,
          watch_time_minutes: Math.round(stats.watch_time / 60),
          likes: stats.likes,
          subscribers_gained: stats.subscribers,
          average_view_duration: stats.views > 0 ? Math.round(stats.watch_time / stats.views) : 0,
          engagement_rate: stats.views > 0 ? (stats.likes / stats.views) * 100 : 0
        });
      }
      continue; // Skip the push below since we already pushed
  }

  normalizedData.push(normalized);
}

return normalizedData;

// Calculate advanced performance metrics and scores
const performances = $input.all();
const analyzedPerformances = [];

// Get historical data for comparison (simulated)
const historicalAverages = {
  twitter: { engagement_rate: 2.5, avg_impressions: 5000 },
  linkedin: { engagement_rate: 3.2, avg_impressions: 3000 },
  youtube: { engagement_rate: 4.1, avg_views: 1000 }
};

for (const perf of performances) {
  const data = perf.json;
  const platform = data.platform;
  const historical = historicalAverages[platform] || {};

  // Calculate performance score (0-100)
  let performanceScore = 0;
  const breakdown = {};

  // Engagement rate component (0-40 points)
  const engagementRate = data.engagement_rate || 0;
  const targetEngagement = historical.engagement_rate || 2.0;
  const engagementRatio = engagementRate / targetEngagement;
  breakdown.engagement_score = Math.min(engagementRatio * 20, 40);

  // Volume component (0-30 points)
  let volumeMetric = data.impressions || data.views || data.reach || 0;
  let targetVolume = historical.avg_impressions || historical.avg_views || 1000;
  const volumeRatio = Math.log10(volumeMetric + 1) / Math.log10(targetVolume + 1);
  breakdown.volume_score = Math.min(volumeRatio * 15, 30);

  // Growth component (0-20 points) - compare with previous period
  const growthRate = data.growth_rate || 0;
  breakdown.growth_score = Math.min(Math.max(growthRate * 10, 0), 20);

  // Quality component (0-10 points)
  const hasVideo = data.has_video || false;
  const hasImage = data.has_image || false;
  const wordCount = data.word_count || 0;
  breakdown.quality_score = (hasVideo ? 4 : 0) + (hasImage ? 3 : 0) + (wordCount > 100 ? 3 : 0);

  // Calculate total
  performanceScore = Object.values(breakdown).reduce((a, b) => a + b, 0);

  // Determine performance tier
  let performanceTier = 'low';
  if (performanceScore >= 80) performanceTier = 'excellent';
  else if (performanceScore >= 65) performanceTier = 'good';
  else if (performanceScore >= 50) performanceTier = 'average';

  // Identify optimization opportunities
  const optimizations = [];
  if (engagementRate < targetEngagement * 0.7) {
    optimizations.push('low_engagement');
  }
  if (volumeMetric < targetVolume * 0.5) {
    optimizations.push('low_reach');
  }
  if (data.engagement_rate > targetEngagement * 1.5) {
    optimizations.push('high_performing');
  }

  analyzedPerformances.push({
    ...data,
    performance_score: performanceScore,
    performance_breakdown: breakdown,
    performance_tier: performanceTier,
    optimization_opportunities: optimizations,
    historical_comparison: {
      engagement_vs_target: engagementRate - targetEngagement,
      volume_vs_target: volumeMetric - targetVolume
    }
  });
}

return analyzedPerformances;

// Generate optimization recommendations based on performance analysis
const performances = $input.all();
const recommendations = [];

for (const perf of performances) {
  const data = perf.json;
  const platform = data.platform;
  const optimizations = data.optimization_opportunities || [];

  let platformRecommendations = [];

  // Platform-specific recommendations
  switch(platform) {
    case 'twitter':
      if (optimizations.includes('low_engagement')) {
        platformRecommendations.push({
          type: 'content',
          action: 'add_visuals',
          priority: 'high',
          description: 'Add images or videos to increase engagement',
          expected_impact: '+15-25% engagement'
        });
        platformRecommendations.push({
          type: 'timing',
          action: 'optimize_post_time',
          priority: 'medium',
          description: 'Post during peak engagement hours (9-11 AM, 1-3 PM)',
          expected_impact: '+10-20% reach'
        });
      }
      if (optimizations.includes('low_reach')) {
        platformRecommendations.push({
          type: 'hashtag',
          action: 'add_trending_hashtags',
          priority: 'high',
          description: 'Include 2-3 trending hashtags',
          expected_impact: '+20-30% impressions'
        });
      }
      break;

    case 'linkedin':
      if (optimizations.includes('low_engagement')) {
        platformRecommendations.push({
          type: 'format',
          action: 'use_carousel',
          priority: 'high',
          description: 'Use carousel format for multiple points',
          expected_impact: '+25-35% engagement'
        });
        platformRecommendations.push({
          type: 'content',
          action: 'add_industry_insights',
          priority: 'medium',
          description: 'Include data or industry insights',
          expected_impact: '+15-25% comments'
        });
      }
      break;

    case 'youtube':
      if (optimizations.includes('low_engagement')) {
        platformRecommendations.push({
          type: 'thumbnail',
          action: 'optimize_thumbnail',
          priority: 'high',
          description: 'Use high-contrast, text-heavy thumbnails',
          expected_impact: '+20-30% CTR'
        });
        platformRecommendations.push({
          type: 'content',
          action: 'add_chapters',
          priority: 'medium',
          description: 'Add timestamps and chapters',
          expected_impact': '+15-25% watch_time'
        });
      }
      break;
  }

  // General recommendations for high performers
  if (optimizations.includes('high_performing')) {
    platformRecommendations.push({
      type: 'amplification',
      action: 'boost_or_repurpose',
      priority: 'high',
      description: 'Boost this content or repurpose for other platforms',
      expected_impact: '+30-50% additional reach'
    });
  }

  if (platformRecommendations.length > 0) {
    recommendations.push({
      content_id: data.content_id,
      platform: platform,
      performance_score: data.performance_score,
      performance_tier: data.performance_tier,
      recommendations: platformRecommendations,
      estimated_impact: platformRecommendations.reduce((sum, rec) => {
        const impact = parseInt(rec.expected_impact) || 0;
        return sum + impact;
      }, 0) / platformRecommendations.length
    });
  }
}

// Sort by estimated impact
recommendations.sort((a, b) => b.estimated_impact - a.estimated_impact);

return recommendations;

// Generate comprehensive performance report
const allData = $input.all();

const report = {
  timestamp: new Date().toISOString(),
  period: 'daily',
  summary: {
    total_content_analyzed: allData.length,
    average_performance_score: 0,
    top_performers: 0,
    underperformers: 0,
    by_platform: {},
    by_tier: {}
  },
  top_performers: [],
  key_insights: [],
  recommendations: []
};

let totalScore = 0;

for (const data of allData) {
  const perf = data.json;
  totalScore += perf.performance_score || 0;

  // Count by platform
  const platform = perf.platform;
  if (!report.summary.by_platform[platform]) {
    report.summary.by_platform[platform] = 0;
  }
  report.summary.by_platform[platform]++;

  // Count by tier
  const tier = perf.performance_tier || 'unknown';
  if (!report.summary.by_tier[tier]) {
    report.summary.by_tier[tier] = 0;
  }
  report.summary.by_tier[tier]++;

  // Track top performers
  if (perf.performance_score >= 80) {
    report.summary.top_performers++;
    report.top_performers.push({
      content_id: perf.content_id,
      platform: platform,
      score: perf.performance_score,
      key_metric: perf.impressions || perf.views || 0
    });
  }

  // Track underperformers
  if (perf.performance_score < 50) {
    report.summary.underperformers++;
  }
}

report.summary.average_performance_score = allData.length > 0 ? 
  Math.round(totalScore / allData.length) : 0;

// Generate insights
if (report.summary.top_performers > 0) {
  report.key_insights.push({
    type: 'positive',
    message: `${report.summary.top_performers} pieces of content are performing exceptionally well`,
    action: 'Consider boosting or repurposing these assets'
  });
}

if (report.summary.underperformers > 0) {
  report.key_insights.push({
    type: 'attention',
    message: `${report.summary.underperformers} pieces of content need optimization`,
    action: 'Review optimization recommendations'
  });
}

// Find best performing platform
const platforms = Object.entries(report.summary.by_platform);
if (platforms.length > 0) {
  const bestPlatform = platforms.reduce((a, b) => a[1] > b[1] ? a : b);
  report.key_insights.push({
    type: 'insight',
    message: `${bestPlatform[0]} has the most content analyzed (${bestPlatform[1]} pieces)`,
    action: 'Consider allocating more resources to this platform'
  });
}

// Send to SIMP broker
const reportPayload = {
  intent_type: 'performance_optimization_report',
  source_agent: 'n8n_workflow',
  target_agent: 'base_media_agent',
  payload: report
};

return {
  json: {
    report: report,
    report_payload: reportPayload,
    should_send_report: true
  }
};

